import hashlib
import time
import uuid
from collections import defaultdict

class InteractionEngine:
    def __init__(self):
        self.user_interactions = defaultdict(list)  # {anonymized_user_id: [interaction_data]}
        self.interaction_types = set()

    def anonymize_user_id(self, user_id):
        """Hashes the user ID to protect privacy."""
        hashed_id = hashlib.sha256(str(user_id).encode('utf-8')).hexdigest()
        return hashed_id

    def record_interaction(self, user_id, interaction_type, interaction_data):
        """Records a user interaction, anonymizing the user ID and validating the data."""

        if not isinstance(interaction_type, str):
            raise ValueError("Interaction type must be a string.")

        if not isinstance(interaction_data, dict):
            raise ValueError("Interaction data must be a dictionary.")

        anonymized_user_id = self.anonymize_user_id(user_id)

        # Validate interaction data (example: check for sensitive info)
        if self.contains_sensitive_data(interaction_data):
            print("Warning: Sensitive data detected in interaction.  Data not recorded.")
            return False

        timestamp = time.time()
        interaction_id = uuid.uuid4()  # Generate a unique ID for each interaction

        interaction_record = {
            'interaction_id': str(interaction_id),
            'interaction_type': interaction_type,
            'timestamp': timestamp,
            'data': self.anonymize_interaction_data(interaction_data)
        }

        self.user_interactions[anonymized_user_id].append(interaction_record)
        self.interaction_types.add(interaction_type)
        return True

    def anonymize_interaction_data(self, data):
        """Anonymizes specific fields in the interaction data (e.g., replace names with placeholders)."""
        anonymized_data = data.copy()  # Create a copy to avoid modifying the original

        # Example anonymization rules (customize as needed):
        if 'name' in anonymized_data:
            anonymized_data['name'] = 'Anonymized User'
        if 'email' in anonymized_data:
            del anonymized_data['email']  # Remove email entirely
        if 'rating' in anonymized_data:
            anonymized_data['rating'] = int(anonymized_data['rating']) #ensure rating is an int

        return anonymized_data

    def contains_sensitive_data(self, data):
        """Checks if the interaction data contains potentially sensitive information."""
        sensitive_keywords = ['password', 'ssn', 'credit_card']  # Expand as needed
        for key, value in data.items():
            if isinstance(value, str):
                if any(keyword in value.lower() for keyword in sensitive_keywords):
                    return True
            elif isinstance(value, list):
                for item in value:
                    if isinstance(item, str) and any(keyword in item.lower() for keyword in sensitive_keywords):
                        return True
        return False

    def get_user_interactions(self, user_id):
        """Retrieves interactions for a user (anonymized ID)."""
        anonymized_user_id = self.anonymize_user_id(user_id)
        return self.user_interactions.get(anonymized_user_id, [])

    def get_interaction_types(self):
        """Returns a set of all recorded interaction types."""
        return self.interaction_types

    def get_interactions_by_type(self, interaction_type):
        """Retrieves all interactions of a specific type."""
        interactions = []
        for user_id, user_interactions in self.user_interactions.items():
            for interaction in user_interactions:
                if interaction['interaction_type'] == interaction_type:
                    interactions.append({
                        'user_id': user_id,
                        'interaction': interaction
                    })
        return interactions

    def clear_user_data(self, user_id):
        """Deletes all interaction data for a given user."""
        anonymized_user_id = self.anonymize_user_id(user_id)
        if anonymized_user_id in self.user_interactions:
            del self.user_interactions[anonymized_user_id]
            return True
        return False

    def get_all_interactions(self):
        """Returns all interactions stored in the system."""
        all_interactions = []
        for user_id, interactions in self.user_interactions.items():
            for interaction in interactions:
                all_interactions.append({
                    'user_id': user_id,
                    'interaction': interaction
                })
        return all_interactions

if __name__ == '__main__':
    engine = InteractionEngine()

    # Example Usage
    user_id_1 = 123
    user_id_2 = 456

    engine.record_interaction(user_id_1, 'rating', {'item_id': 'product1', 'rating': 5, 'comment': 'Great product!'})
    engine.record_interaction(user_id_1, 'upload', {'file_name': 'image.jpg', 'file_size': 1024})
    engine.record_interaction(user_id_2, 'context_modification', {'new_theme': 'dark', 'font_size': 12})
    engine.record_interaction(user_id_2, 'rating', {'item_id': 'product2', 'rating': 4, 'comment': 'Good value.'})
    engine.record_interaction(user_id_1, 'profile_update', {'name': 'John Doe', 'email': 'john.doe@example.com', 'city': 'New York'})

    print("Interaction Types:", engine.get_interaction_types())

    user1_interactions = engine.get_user_interactions(user_id_1)
    print(f"User {user_id_1} Interactions:", user1_interactions)

    rating_interactions = engine.get_interactions_by_type('rating')
    print("Rating Interactions:", rating_interactions)

    all_interactions = engine.get_all_interactions()
    print("All Interactions:", all_interactions)

    engine.clear_user_data(user_id_1)
    print(f"User {user_id_1} Interactions after clearing:", engine.get_user_interactions(user_id_1))

