import hashlib
import time
import uuid
from collections import defaultdict

class InteractionTracker:
    def __init__(self):
        self.user_interactions = defaultdict(list)  # {hashed_user_id: [interaction_data]}
        self.interaction_types = {
            "like",
            "rating",
            "upload",
            "settings_change",
        }  # Set of valid interaction types

    def hash_user_id(self, user_id):
        """Hashes the user ID for anonymization."""
        hashed_id = hashlib.sha256(str(user_id).encode('utf-8')).hexdigest()
        return hashed_id

    def anonymize_data(self, data, fields_to_anonymize=None):
        """Anonymizes specific fields in the interaction data."""
        if fields_to_anonymize is None:
            return data  # No anonymization needed

        anonymized_data = data.copy()
        for field in fields_to_anonymize:
            if field in anonymized_data:
                anonymized_data[field] = hashlib.sha256(str(anonymized_data[field]).encode('utf-8')).hexdigest()
        return anonymized_data

    def track_interaction(self, user_id, interaction_type, interaction_data=None, anonymize_fields=None):
        """Tracks a user interaction.

        Args:
            user_id: The unique identifier of the user.
            interaction_type: The type of interaction (e.g., "like", "rating").
            interaction_data: A dictionary containing data related to the interaction.
            anonymize_fields: A list of fields in interaction_data to anonymize.
        """
        if interaction_type not in self.interaction_types:
            print(f"Warning: Invalid interaction type: {interaction_type}")
            return  # Or raise an exception

        hashed_user_id = self.hash_user_id(user_id)
        timestamp = time.time()

        interaction_record = {
            "interaction_id": uuid.uuid4().hex,  # Unique ID for each interaction
            "timestamp": timestamp,
            "interaction_type": interaction_type,
        }

        if interaction_data:
            anonymized_interaction_data = self.anonymize_data(interaction_data, anonymize_fields)
            interaction_record["data"] = anonymized_interaction_data
        else:
            interaction_record["data"] = {}

        self.user_interactions[hashed_user_id].append(interaction_record)

    def get_user_interactions(self, user_id):
        """Retrieves all interactions for a given user."""
        hashed_user_id = self.hash_user_id(user_id)
        return self.user_interactions.get(hashed_user_id, [])

    def get_interactions_by_type(self, interaction_type):
        """Retrieves all interactions of a specific type."""
        interactions = []
        for user_interactions in self.user_interactions.values():
            for interaction in user_interactions:
                if interaction["interaction_type"] == interaction_type:
                    interactions.append(interaction)
        return interactions

    def add_interaction_type(self, interaction_type):
        """Adds a new valid interaction type."""
        self.interaction_types.add(interaction_type)

    def remove_user_data(self, user_id):
        """Removes all data associated with a user."""
        hashed_user_id = self.hash_user_id(user_id)
        if hashed_user_id in self.user_interactions:
            del self.user_interactions[hashed_user_id]

    def clear_all_data(self):
        """Clears all stored interaction data."""
        self.user_interactions.clear()

if __name__ == '__main__':
    tracker = InteractionTracker()

    # Example Usage
    user_id_1 = 123
    user_id_2 = 456

    tracker.track_interaction(user_id_1, "like", {"item_id": "abc", "timestamp": time.time()})
    tracker.track_interaction(user_id_1, "rating", {"item_id": "def", "rating": 4, "comment": "Good product"}, anonymize_fields=["comment"])
    tracker.track_interaction(user_id_2, "upload", {"file_name": "image.jpg", "file_size": 1024})
    tracker.track_interaction(user_id_2, "settings_change", {"setting": "theme", "new_value": "dark"})

    print("User 1 Interactions:", tracker.get_user_interactions(user_id_1))
    print("User 2 Interactions:", tracker.get_user_interactions(user_id_2))
