        self.interaction_types = {
            "like": self._process_like,
            "rating": self._process_rating,
            "upload": self._process_upload,
            "settings_change": self._process_settings_change,
        }

    def register_interaction_type(self, interaction_type, processing_function):
        """
        Registers a new interaction type and its associated processing function.

        Args:
            interaction_type (str): The name of the new interaction type.
            processing_function (callable): A function that processes the interaction data.
                                            It should take the interaction data as input.
        """
        if interaction_type in self.interaction_types:
            raise ValueError(f"Interaction type '{interaction_type}' already exists.")
        self.interaction_types[interaction_type] = processing_function

    def process_interaction(self, user_id, interaction_type, data):
        """
        Processes a user interaction.

        Args:
            user_id (str): The unique identifier of the user.
            interaction_type (str): The type of interaction (e.g., "like", "rating").
            data (dict): A dictionary containing the interaction data.

        Returns:
            bool: True if the interaction was processed successfully, False otherwise.
        """
        if not isinstance(user_id, str):
            raise TypeError("user_id must be a string.")
        if not isinstance(interaction_type, str):
            raise TypeError("interaction_type must be a string.")
        if not isinstance(data, dict):
            raise TypeError("data must be a dictionary.")

        if interaction_type not in self.interaction_types:
            print(f"Warning: Unknown interaction type '{interaction_type}'.  Ignoring.")
            return False

