import hashlib
import uuid
import datetime
import json

class RailwayLocomotive:
    def __init__(self):
        self.interactions = []
        self.user_profiles = {}  # Store anonymized user profiles

    def _anonymize_user_id(self, user_id):
        """Hashes the user ID to protect privacy."""
        hashed_id = hashlib.sha256(str(user_id).encode('utf-8')).hexdigest()
        return hashed_id

    def _generate_interaction_id(self):
        """Generates a unique ID for each interaction."""
        return str(uuid.uuid4())

    def register_user(self, user_id):
        """Registers a new user and creates an anonymized profile."""
        anonymized_id = self._anonymize_user_id(user_id)
        if anonymized_id not in self.user_profiles:
            self.user_profiles[anonymized_id] = {
                'registration_date': datetime.datetime.now().isoformat(),
                'interaction_count': 0,
                'last_active': None
            }
            return True
        else:
            return False #User already registered

    def record_interaction(self, user_id, interaction_type, data=None):
        """Records an interaction, anonymizing user ID and interaction data where appropriate."""
        anonymized_user_id = self._anonymize_user_id(user_id)
        interaction_id = self._generate_interaction_id()
        timestamp = datetime.datetime.now().isoformat()

        interaction = {
            'interaction_id': interaction_id,
            'user_id': anonymized_user_id,
            'interaction_type': interaction_type,
            'timestamp': timestamp,
            'data': self._anonymize_interaction_data(interaction_type, data)  # Anonymize data based on type
        }

        self.interactions.append(interaction)

        # Update user profile
        if anonymized_user_id in self.user_profiles:
            self.user_profiles[anonymized_user_id]['interaction_count'] += 1
            self.user_profiles[anonymized_user_id]['last_active'] = timestamp
        else:
            print(f"Warning: User {user_id} not registered. Interaction recorded, but user profile not updated.")

        return interaction_id

    def _anonymize_interaction_data(self, interaction_type, data):
        """Anonymizes interaction data based on the interaction type.
           This is a crucial part for privacy.  Implement specific anonymization
           strategies for each interaction type.
        """
        if data is None:
            return None

        if interaction_type == 'like':
            # No specific anonymization needed for likes (just the user ID is enough)
            return {}  # Return empty dict to avoid storing unnecessary data

        elif interaction_type == 'rating':
            # Could bucket ratings (e.g., 1-2 stars, 3-4 stars, 5 stars)
            if 'rating' in data:
                rating = data['rating']
                if 1 <= rating <= 2:
                    bucketed_rating = '1-2'
                elif 3 <= rating <= 4:
                    bucketed_rating = '3-4'
                elif rating == 5:
                    bucketed_rating = '5'
                else:
                    bucketed_rating = 'invalid' #Handle invalid ratings
                return {'rating_bucket': bucketed_rating}
            else:
                return {}

        elif interaction_type == 'upload':
            # Store only metadata, not the actual file.  Hash the filename.
            if 'filename' in data:
                hashed_filename = hashlib.sha256(data['filename'].encode('utf-8')).hexdigest()
                return {'hashed_filename': hashed_filename, 'file_type': data.get('file_type', 'unknown')} #Store file type if available
            else:
                return {}

        elif interaction_type == 'scene_change':
            # Store scene ID, but potentially anonymize scene names if needed
            if 'scene_id' in data:
                return {'scene_id': data['scene_id']}
            else:
                return {}

        else:
            # Unknown interaction type:  Log and return empty dict to avoid storing potentially sensitive data.
            print(f"Warning: Unknown interaction type '{interaction_type}'.  Data not stored.")
            return {}

    def get_user_interactions(self, user_id):
        """Retrieves interactions for a given user (anonymized ID)."""
        anonymized_user_id = self._anonymize_user_id(user_id)
        return [interaction for interaction in self.interactions if interaction['user_id'] == anonymized_user_id]

    def get_interaction_by_id(self, interaction_id):
        """Retrieves an interaction by its ID."""
        for interaction in self.interactions:
            if interaction['interaction_id'] == interaction_id:
                return interaction
        return None

    def get_all_interactions(self):
        """Returns all interactions (for admin/analysis purposes, with appropriate access control)."""
        return self.interactions

    def get_user_profile(self, user_id):
        """Retrieves the anonymized user profile."""
        anonymized_user_id = self._anonymize_user_id(user_id)
        return self.user_profiles.get(anonymized_user_id)

    def delete_user_data(self, user_id):
        """Deletes all data associated with a user (anonymized ID)."""
        anonymized_user_id = self._anonymize_user_id(user_id)

        # Remove interactions
        self.interactions = [interaction for interaction in self.interactions if interaction['user_id'] != anonymized_user_id]

        # Remove user profile
        if anonymized_user_id in self.user_profiles:
            del self.user_profiles[anonymized_user_id]

    def to_json(self):
        """Serializes the data to JSON format."""
        return json.dumps({
            'interactions': self.interactions,
            'user_profiles': self.user_profiles
        }, indent=4)

    def from_json(self, json_data):
        """Loads data from a JSON string."""
        data = json.loads(json_data)
        self.interactions = data.get('interactions', [])
        self.user_profiles = data.get('user_profiles', {})

